11398846,-0.02395369,0.00860766,0.07637205,-0.00969289,-0.00281194,0.09209570,0.07258856,-0.00644546,0.00706863,0.07131912,-0.03117730,0.05692006,-0.00001506,0.03973015,0.00228002,0.00526390,-0.05841276,-0.00362938,0.02948418,-0.02239738,0.00228760,0.04167148,-0.05522234,-0.03346365,-0.01734398,-0.07798482,0.00867472,-0.00881151,-0.01064076,-0.02188860,0.02079557,0.02384660,0.02743334,-0.01768550,-0.00476049,0.02290008,-0.04918613,0.06926937,-0.00982517,0.12557587,-0.02702934,0.02959752]',E'Use the Python interpreter to run your application\n\nobject SimpleApp {\n  def main(args: Array[String]): Unit = {\n    val logFile = "YOUR_SPARK_HOME/README.md" // Should be some file on your system\n    val spark = SparkSession.builder.appName("Simple Application").getOrCreate()\n    val logData = spark.read.textFile(logFile).cache()\n    val numAs = logData.filter(line => line.contains("a")).count()\n    val numBs = logData.filter(line => line.contains("b")).count()\n    println(s"Lines with a: $numAs, Lines with b: $numBs")\n    spark.stop()\n  }\n}','{"source": "spark", "version": "3.5", "language": "python", "title": "Interactive Analysis with the Spark Shell", "section_title": "quick-start", "url": "https://github.com/apache/spark/blob/master/docs/quick-start.md", "topics": "spark,bigdata,sql,quick,start", "categories": "bigdata,analytics,ml,streaming"}');
